import { Component, OnInit, ViewChild } from '@angular/core';
import { ModalController } from '@ionic/angular';
import { IonSlides } from '@ionic/angular';
import { UserService } from '../services/user.service';
import { ImageZoomPage } from './../image-zoom/image-zoom.page';

@Component({
  selector: 'app-order',
  templateUrl: './order.page.html',
  styleUrls: ['./order.page.scss'],
})
export class OrderPage implements OnInit {

  @ViewChild('slidesRef', { static: true }) slidesRef: IonSlides;

  constructor(private userService:UserService, private modalCtrl: ModalController) { }

  public order_id:any;
  public is_load:boolean = false;

  public order_info: any;

  public options = {
    keyboard: true,
    spaceBetween:3,
  }

  public images: any = [
    '../../assets/item_big.png',
    '../../assets/item_big.png',
    '../../assets/item_big.png',
    '../../assets/item_big.png',
  ]

  ngOnInit() {
    console.log(this.order_id);
    this.userService.loadLead(this.order_id).then( response =>{
      this.order_info = response;
      console.log(this.order_info);
      this.is_load = true;
    })
  }

  close() {
    this.modalCtrl.dismiss();
  }


  public slideWillChange() {
    console.log('Slide will change');
  }

  public async slideDidChange() {
    console.log('Slide did change');

    if (!this.slidesRef) return;

    console.table({
      isBeginning: await this.slidesRef.isBeginning(),
      isEnd: await this.slidesRef.isEnd()
    });
  }

  slidePrev() {
    this.slidesRef.slidePrev();
  }

  slideNext() {
    this.slidesRef.slideNext();
  }

  async openPreview() {
    const modal = await this.modalCtrl.create({
      component: ImageZoomPage,
      componentProps: {img: this.order_info.deal_detail.IMAGE},
      cssClass: 'transparent-modal'
    });
    modal.present();
  }

}
